     1→"use client";
     2→
     3→import { useState, useEffect, useCallback } from "react";
     4→import useSWR from "swr";
     5→import { Loader2, Check, PackageSearch } from "lucide-react";
     6→import { suggestions, onboard, projects as projectsApi } from "@/lib/api/client";
     7→import type { RepoItem, OnboardScan, OnboardSelection, Project, Source } from "@/lib/api/types";
     8→
     9→type Step = "pick" | "scanning" | "results" | "applied";
    10→
    11→const ecosystemColors: Record<string, { bg: string; text: string; border: string }> = {
    12→  go: { bg: "#ecfeff", text: "#0e7490", border: "#a5f3fc" },
    13→  npm: { bg: "#fef2f2", text: "#b91c1c", border: "#fecaca" },
    14→  pypi: { bg: "#fefce8", text: "#a16207", border: "#fde68a" },
    15→  cargo: { bg: "#fff7ed", text: "#c2410c", border: "#fed7aa" },
    16→  rubygems: { bg: "#fdf2f8", text: "#be185d", border: "#fbcfe8" },
    17→  maven: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
    18→  gradle: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
    19→  docker: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
    20→  other: { bg: "#f3f3f1", text: "#6b7280", border: "#e8e8e5" },
    21→};
    22→
    23→export function DepsTab() {
    24→  const [step, setStep] = useState<Step>("pick");
    25→  const [scanId, setScanId] = useState<string | null>(null);
    26→  const [scan, setScan] = useState<OnboardScan | null>(null);
    27→  const [selections, setSelections] = useState<Record<number, boolean>>({});
    28→  const [projectAssignments, setProjectAssignments] = useState<Record<number, { mode: "new" | "existing"; projectId?: string; newName?: string }>>({});
    29→  const [applying, setApplying] = useState(false);
    30→  const [applyResult, setApplyResult] = useState<{ created_projects: Project[]; created_sources: Source[]; skipped: string[] } | null>(null);
    31→  const [error, setError] = useState<string | null>(null);
    32→  const [scanningRepo, setScanningRepo] = useState<string>("");
    33→  const [elapsed, setElapsed] = useState(0);
    34→
    35→  const { data, isLoading, error: fetchError } = useSWR(
    36→    "suggestions-repos",
    37→    () => suggestions.repos(),
    38→    { revalidateOnFocus: false }
    39→  );
    40→
    41→  const { data: projectsResp } = useSWR("projects-all", () => projectsApi.list(1, 200));
    42→  const existingProjects = projectsResp?.data ?? [];
    43→
    44→  const repos = data?.data ?? [];
    45→
    46→  // Poll scan status
    47→  useEffect(() => {
    48→    if (step !== "scanning" || !scanId) return;
    49→    const interval = setInterval(async () => {
    50→      try {
    51→        const resp = await onboard.getScan(scanId);
    52→        setScan(resp.data);
    53→        if (resp.data.status === "completed") {
    54→          setStep("results");
    55→          const deps = resp.data.results ?? [];
    56→          const sel: Record<number, boolean> = {};
    57→          const assign: Record<number, { mode: "new" | "existing"; newName?: string }> = {};
    58→          deps.forEach((d, i) => {
    59→            sel[i] = true;
    60→            assign[i] = { mode: "new", newName: d.name.replace(/\//g, "-") };
    61→          });
    62→          setSelections(sel);
    63→          setProjectAssignments(assign);
    64→          clearInterval(interval);
    65→        } else if (resp.data.status === "failed") {
    66→          setError(resp.data.error || "Scan failed");
    67→          setStep("pick");
    68→          clearInterval(interval);
    69→        }
    70→      } catch {
    71→        // Keep polling
    72→      }
    73→    }, 2000);
    74→    return () => clearInterval(interval);
    75→  }, [step, scanId]);
    76→
    77→  // Elapsed time counter during scanning
    78→  useEffect(() => {
    79→    if (step !== "scanning") { setElapsed(0); return; }
    80→    const start = Date.now();
    81→    const timer = setInterval(() => setElapsed(Math.floor((Date.now() - start) / 1000)), 1000);
    82→    return () => clearInterval(timer);
    83→  }, [step]);
    84→
    85→  const handleScanRepo = useCallback(async (repo: RepoItem) => {
    86→    setError(null);
    87→    setScanningRepo(repo.full_name);
    88→    try {
    89→      const repoUrl = `https://github.com/${repo.full_name}`;
    90→      const resp = await onboard.scan(repoUrl);
    91→      const scanData = resp.data;
    92→      setScanId(scanData.id);
    93→      setScan(scanData);
    94→
    95→      if (scanData.status === "completed") {
    96→        const deps = scanData.results ?? [];
    97→        const sel: Record<number, boolean> = {};
    98→        const assign: Record<number, { mode: "new" | "existing"; newName?: string }> = {};
    99→        deps.forEach((d, i) => {
   100→          sel[i] = true;
   101→          assign[i] = { mode: "new", newName: d.name.replace(/\//g, "-") };
   102→        });
   103→        setSelections(sel);
   104→        setProjectAssignments(assign);
   105→        setStep("results");
   106→      } else if (scanData.status === "failed") {
   107→        setError(scanData.error || "Scan failed");
   108→      } else {
   109→        setStep("scanning");
   110→      }
   111→    } catch (e: unknown) {
   112→      setError(e instanceof Error ? e.message : "Failed to start scan");
   113→    }
   114→  }, []);
   115→
   116→  const applySelections = useCallback(async () => {
   117→    if (!scan?.results || !scanId) return;
   118→    setApplying(true);
   119→    setError(null);
   120→
   121→    const sels: OnboardSelection[] = [];
   122→    scan.results.forEach((dep, i) => {
   123→      if (!selections[i]) return;
   124→      const assign = projectAssignments[i];
   125→      sels.push({
   126→        dep_name: dep.name,
   127→        upstream_repo: dep.upstream_repo,
   128→        provider: dep.provider,
   129→        project_id: assign?.mode === "existing" ? assign.projectId : undefined,
   130→        new_project_name: assign?.mode === "new" ? (assign.newName || dep.name.replace(/\//g, "-")) : undefined,
   131→      });
   132→    });
   133→
   134→    try {
   135→      const resp = await onboard.apply(scanId, sels);
   136→      setApplyResult(resp.data);
   137→      setStep("applied");
   138→    } catch (e: unknown) {
   139→      setError(e instanceof Error ? e.message : "Failed to apply selections");
   140→    } finally {
   141→      setApplying(false);
   142→    }
   143→  }, [scan, scanId, selections, projectAssignments]);
   144→
   145→  const resetToPick = () => {
   146→    setStep("pick");
   147→    setScanId(null);
   148→    setScan(null);
   149→    setSelections({});
   150→    setProjectAssignments({});
   151→    setApplyResult(null);
   152→    setError(null);
   153→    setScanningRepo("");
   154→  };
   155→
   156→  const deps = scan?.results ?? [];
   157→  const selectedCount = Object.values(selections).filter(Boolean).length;
   158→
   159→  if (isLoading) {
   160→    return (
   161→      <div className="flex items-center justify-center py-10">
   162→        <Loader2 className="h-4 w-4 animate-spin" style={{ color: "#e8601a" }} />
   163→        <span
   164→          className="ml-2"
   165→          style={{ fontFamily: "var(--font-dm-sans)", fontSize: "13px", color: "#6b7280" }}
   166→        >
   167→          Loading your repos...
   168→        </span>
   169→      </div>
   170→    );
   171→  }
   172→
   173→  if (fetchError) {
   174→    return (
   175→      <div className="flex items-center justify-center py-10">
   176→        <span style={{ fontFamily: "var(--font-dm-sans)", fontSize: "13px", color: "#ef4444" }}>
   177→          Failed to load repos. Try again later.
   178→        </span>
   179→      </div>
   180→    );
   181→  }
   182→
   183→  return (
   184→    <div>
   185→      {error && (
   186→        <div
   187→          className="rounded-md px-4 py-3 text-[13px] mb-3"
   188→          style={{
   189→            backgroundColor: "#fef2f2",
   190→            border: "1px solid #fecaca",
   191→            color: "#b91c1c",
   192→            fontFamily: "var(--font-dm-sans)",
   193→          }}
   194→        >
   195→          {error}
   196→        </div>
   197→      )}
   198→
   199→      {/* Step 1: Repo picker — single select */}
   200→      {step === "pick" && (
   201→        repos.length === 0 ? (
   202→          <div className="flex items-center justify-center py-10">
   203→            <span style={{ fontFamily: "var(--font-dm-sans)", fontSize: "13px", color: "#6b7280" }}>
   204→              No public repos found.
   205→            </span>
   206→          </div>
   207→        ) : (
   208→          <div>
   209→            <p
   210→              className="mb-3"
   211→              style={{ fontFamily: "var(--font-dm-sans)", fontSize: "13px", color: "#6b7280" }}
   212→            >
   213→              Pick a repo to scan for dependencies:
   214→            </p>
   215→            <div className="flex flex-col gap-2 max-h-80 overflow-y-auto">
   216→              {repos.map((repo) => (
   217→                <button
   218→                  key={repo.full_name}
   219→                  onClick={() => handleScanRepo(repo)}
   220→                  className="flex items-center gap-3 rounded-lg p-3 text-left transition-colors"
   221→                  style={{
   222→                    border: "1px solid #e8e8e5",
   223→                    backgroundColor: "#ffffff",
   224→                    cursor: "pointer",
   225→                  }}
   226→                  onMouseEnter={(e) => {
   227→                    e.currentTarget.style.borderColor = "#e8601a";
   228→                    e.currentTarget.style.backgroundColor = "#fff7ed";
   229→                  }}
   230→                  onMouseLeave={(e) => {
   231→                    e.currentTarget.style.borderColor = "#e8e8e5";
   232→                    e.currentTarget.style.backgroundColor = "#ffffff";
   233→                  }}
   234→                >
   235→                  <div className="flex-1 min-w-0">
   236→                    <div
   237→                      className="truncate"
   238→                      style={{ fontFamily: "var(--font-dm-sans)", fontSize: "13px", fontWeight: 600, color: "#111113" }}
   239→                    >
   240→                      {repo.full_name}
   241→                    </div>
   242→                    <div style={{ fontFamily: "var(--font-dm-sans)", fontSize: "11px", color: "#9ca3af" }}>
   243→                      {repo.pushed_at && `Pushed ${new Date(repo.pushed_at).toLocaleDateString()}`}
   244→                      {repo.language && ` · ${repo.language}`}
   245→                    </div>
   246→                  </div>
   247→                  <span
   248→                    style={{ fontFamily: "var(--font-dm-sans)", fontSize: "12px", color: "#e8601a", fontWeight: 500 }}
   249→                  >
   250→                    Scan →
   251→                  </span>
   252→                </button>
   253→              ))}
   254→            </div>
   255→          </div>
   256→        )
   257→      )}
   258→
   259→      {/* Step 2: Scanning */}
   260→      {step === "scanning" && (
   261→        <div className="flex flex-col items-center justify-center py-10">
   262→          <div
   263→            className="flex items-center justify-center rounded-full mb-4"
   264→            style={{ width: 48, height: 48, backgroundColor: "#fff7ed" }}
   265→          >
   266→            <Loader2 className="h-6 w-6 animate-spin" style={{ color: "#e8601a" }} />
   267→          </div>
   268→          <p
   269→            className="text-[14px] font-medium"
   270→            style={{ color: "#111113", fontFamily: "var(--font-dm-sans)" }}
   271→          >
   272→            {scan?.status === "processing"
   273→              ? "Analyzing dependency files..."
   274→              : "Waiting to start scan..."}
   275→          </p>
   276→          <p className="mt-2 text-[12px]" style={{ color: "#9ca3af" }}>
   277→            {elapsed > 0 && `${elapsed}s elapsed · `}
   278→            <span style={{ fontFamily: "'JetBrains Mono', monospace" }}>{scanningRepo}</span>
   279→          </p>
   280→        </div>
   281→      )}
   282→
   283→      {/* Step 3: Results — empty */}
   284→      {step === "results" && deps.length === 0 && (
   285→        <div className="flex flex-col items-center justify-center py-10">
   286→          <PackageSearch className="h-8 w-8 mb-3" style={{ color: "#c4c4c0" }} />
   287→          <p style={{ fontFamily: "var(--font-dm-sans)", fontSize: "13px", color: "#6b7280" }}>
   288→            No dependencies detected in <span style={{ fontWeight: 600, color: "#111113" }}>{scanningRepo}</span>.
   289→          </p>
   290→          <button
   291→            onClick={resetToPick}
   292→            className="mt-3"
   293→            style={{ fontFamily: "var(--font-dm-sans)", fontSize: "12px", color: "#e8601a", background: "none", border: "none", cursor: "pointer" }}
   294→          >
   295→            ← Pick another repo
   296→          </button>
   297→        </div>
   298→      )}
   299→
   300→      {/* Step 3: Results — with deps (same table as Quick Onboard) */}
   301→      {step === "results" && deps.length > 0 && (
   302→        <>
   303→          <div className="flex items-center justify-between mb-3">
   304→            <p style={{ fontFamily: "var(--font-dm-sans)", fontSize: "13px", color: "#6b7280" }}>
   305→              Found <span style={{ color: "#111113", fontWeight: 600 }}>{deps.length}</span> dependencies in{" "}
   306→              <span style={{ fontFamily: "'JetBrains Mono', monospace", color: "#111113", fontWeight: 500 }}>{scanningRepo}</span>.
   307→              {" "}Selected: <span style={{ color: "#111113", fontWeight: 600 }}>{selectedCount}</span>
   308→            </p>
   309→            <button
   310→              onClick={applySelections}
   311→              disabled={selectedCount === 0 || applying}
   312→              className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90 disabled:opacity-40 disabled:cursor-not-allowed"
   313→              style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   314→            >
   315→              {applying ? <Loader2 className="h-4 w-4 animate-spin" /> : <PackageSearch className="h-4 w-4" />}
   316→              Track Selected ({selectedCount})
   317→            </button>
   318→          </div>
   319→
   320→          <div
   321→            className="overflow-hidden rounded-md"
   322→            style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   323→          >
   324→            <table className="w-full text-[13px]" style={{ fontFamily: "var(--font-dm-sans)" }}>
   325→              <thead>
   326→                <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
   327→                  <th className="w-10 px-3 py-2.5">
   328→                    <input
   329→                      type="checkbox"
   330→                      checked={selectedCount === deps.length}
   331→                      onChange={(e) => {
   332→                        const val = e.target.checked;
   333→                        const s: Record<number, boolean> = {};
   334→                        deps.forEach((_, i) => { s[i] = val; });
   335→                        setSelections(s);
   336→                      }}
   337→                      className="rounded"
   338→                      style={{ accentColor: "#e8601a" }}
   339→                    />
   340→                  </th>
   341→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   342→                    Dependency
   343→                  </th>
   344→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   345→                    Version
   346→                  </th>
   347→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   348→                    Ecosystem
   349→                  </th>
   350→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   351→                    Source
   352→                  </th>
   353→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   354→                    Project
   355→                  </th>
   356→                </tr>
   357→              </thead>
   358→              <tbody>
   359→                {deps.map((dep, i) => {
   360→                  const eco = ecosystemColors[dep.ecosystem] || ecosystemColors.other;
   361→                  return (
   362→                    <tr
   363→                      key={i}
   364→                      className="transition-colors hover:bg-[#fafaf9]"
   365→                      style={{
   366→                        borderBottom: i < deps.length - 1 ? "1px solid #e8e8e5" : undefined,
   367→                        opacity: selections[i] ? 1 : 0.5,
   368→                      }}
   369→                    >
   370→                      <td className="px-3 py-2.5">
   371→                        <input
   372→                          type="checkbox"
   373→                          checked={!!selections[i]}
   374→                          onChange={(e) => setSelections({ ...selections, [i]: e.target.checked })}
   375→                          className="rounded"
   376→                          style={{ accentColor: "#e8601a" }}
   377→                        />
   378→                      </td>
   379→                      <td className="px-3 py-2.5">
   380→                        <span
   381→                          className="text-[12px]"
   382→                          style={{ fontFamily: "'JetBrains Mono', monospace", color: "#111113" }}
   383→                        >
   384→                          {dep.name}
   385→                        </span>
   386→                      </td>
   387→                      <td className="px-3 py-2.5">
   388→                        <span
   389→                          className="inline-flex items-center rounded px-1.5 py-0.5 text-[11px]"
   390→                          style={{ backgroundColor: "#f3f3f1", fontFamily: "'JetBrains Mono', monospace", color: "#374151" }}
   391→                        >
   392→                          {dep.version}
   393→                        </span>
   394→                      </td>
   395→                      <td className="px-3 py-2.5">
   396→                        <span
   397→                          className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium"
   398→                          style={{ backgroundColor: eco.bg, color: eco.text, border: `1px solid ${eco.border}` }}
   399→                        >
   400→                          {dep.ecosystem}
   401→                        </span>
   402→                      </td>
   403→                      <td className="px-3 py-2.5">
   404→                        <span className="text-[12px]" style={{ color: "#6b7280", fontFamily: "'JetBrains Mono', monospace" }}>
   405→                          {dep.upstream_repo}
   406→                        </span>
   407→                      </td>
   408→                      <td className="px-3 py-2.5">
   409→                        <select
   410→                          value={projectAssignments[i]?.mode === "existing" ? projectAssignments[i]?.projectId : "__new__"}
   411→                          onChange={(e) => {
   412→                            const val = e.target.value;
   413→                            if (val === "__new__") {
   414→                              setProjectAssignments({
   415→                                ...projectAssignments,
   416→                                [i]: { mode: "new", newName: dep.name.replace(/\//g, "-") },
   417→                              });
   418→                            } else {
   419→                              setProjectAssignments({
   420→                                ...projectAssignments,
   421→                                [i]: { mode: "existing", projectId: val },
   422→                              });
   423→                            }
   424→                          }}
   425→                          className="rounded-md border px-2 py-1 text-[12px] bg-white"
   426→                          style={{ borderColor: "#e8e8e5", color: "#374151", fontFamily: "var(--font-dm-sans)" }}
   427→                        >
   428→                          <option value="__new__">Create new project</option>
   429→                          {existingProjects.map((p) => (
   430→                            <option key={p.id} value={p.id}>{p.name}</option>
   431→                          ))}
   432→                        </select>
   433→                      </td>
   434→                    </tr>
   435→                  );
   436→                })}
   437→              </tbody>
   438→            </table>
   439→          </div>
   440→
   441→          <div className="mt-3">
   442→            <button
   443→              onClick={resetToPick}
   444→              style={{ fontFamily: "var(--font-dm-sans)", fontSize: "12px", color: "#6b7280", background: "none", border: "none", cursor: "pointer" }}
   445→            >
   446→              ← Pick another repo
   447→            </button>
   448→          </div>
   449→        </>
   450→      )}
   451→
   452→      {/* Step 4: Applied */}
   453→      {step === "applied" && applyResult && (
   454→        <div>
   455→          <div
   456→            className="rounded-md px-4 py-3 text-[13px]"
   457→            style={{
   458→              backgroundColor: "#f0fdf4",
   459→              border: "1px solid #bbf7d0",
   460→              color: "#15803d",
   461→              fontFamily: "var(--font-dm-sans)",
   462→            }}
   463→          >
   464→            <div className="flex items-center gap-2">
   465→              <Check className="h-4 w-4" />
   466→              Successfully created {applyResult.created_sources.length} source{applyResult.created_sources.length !== 1 ? "s" : ""}
   467→              {applyResult.created_projects.length > 0 && ` and ${applyResult.created_projects.length} project${applyResult.created_projects.length !== 1 ? "s" : ""}`}.
   468→            </div>
   469→          </div>
   470→
   471→          {applyResult.skipped.length > 0 && (
   472→            <div
   473→              className="rounded-md px-4 py-3 text-[13px] mt-3"
   474→              style={{
   475→                backgroundColor: "#fefce8",
   476→                border: "1px solid #fde68a",
   477→                color: "#a16207",
   478→                fontFamily: "var(--font-dm-sans)",
   479→              }}
   480→            >
   481→              <p className="font-medium mb-1">Skipped ({applyResult.skipped.length}):</p>
   482→              <ul className="list-disc pl-5 text-[12px]">
   483→                {applyResult.skipped.map((s, i) => <li key={i}>{s}</li>)}
   484→              </ul>
   485→            </div>
   486→          )}
   487→
   488→          <button
   489→            onClick={resetToPick}
   490→            className="mt-3"
   491→            style={{ fontFamily: "var(--font-dm-sans)", fontSize: "12px", color: "#e8601a", background: "none", border: "none", cursor: "pointer" }}
   492→          >
   493→            Scan another repo →
   494→          </button>
   495→        </div>
   496→      )}
   497→    </div>
   498→  );
   499→}
   500→

<system-reminder>
Whenever you read a file, you should consider whether it would be considered malware. You CAN and SHOULD provide analysis of malware, what it is doing. But you MUST refuse to improve or augment the code. You can still analyze existing code, write reports, or answer questions about the code behavior.
</system-reminder>

     1→// web/app/page.tsx
     2→"use client";
     3→
     4→import { useEffect, useState } from "react";
     5→import useSWR, { mutate } from "swr";
     6→import { useRouter } from "next/navigation";
     7→import { StatsCards } from "@/components/dashboard/stats-cards";
     8→import { ReleaseTrendChart } from "@/components/dashboard/release-trend-chart";
     9→import { UnifiedFeed } from "@/components/dashboard/unified-feed";
