   333→              disabled={selectedCount === 0 || applying}
   334→              className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90 disabled:opacity-40"
   335→              style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   336→            >
   337→              {applying ? <Loader2 className="h-4 w-4 animate-spin" /> : <PackageSearch className="h-4 w-4" />}
   338→              Track Selected ({selectedCount})
   339→            </button>
   340→          </div>
   341→
   342→          <div
   343→            className="overflow-hidden rounded-md"
   344→            style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   345→          >
   346→            <table className="w-full text-[13px]" style={{ fontFamily: "var(--font-dm-sans)" }}>
   347→              <thead>
   348→                <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
   349→                  <th className="w-10 px-3 py-2.5">
   350→                    <input
   351→                      type="checkbox"
   352→                      checked={selectedCount === deps.length}
   353→                      onChange={(e) => {
   354→                        const val = e.target.checked;
   355→                        const s: Record<number, boolean> = {};
   356→                        deps.forEach((_, i) => { s[i] = val; });
   357→                        setSelections(s);
   358→                      }}
   359→                      className="rounded"
   360→                      style={{ accentColor: "#e8601a" }}
   361→                    />
   362→                  </th>
   363→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   364→                    Dependency
   365→                  </th>
   366→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   367→                    Version
   368→                  </th>
   369→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   370→                    Ecosystem
   371→                  </th>
   372→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   373→                    Source
   374→                  </th>
   375→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   376→                    Project
   377→                  </th>
   378→                </tr>
   379→              </thead>
