   381→                {deps.map((dep, i) => {
   382→                  const eco = ecosystemColors[dep.ecosystem] || ecosystemColors.other;
   383→                  return (
   384→                    <tr
   385→                      key={i}
   386→                      className="transition-colors hover:bg-[#fafaf9]"
   387→                      style={{
   388→                        borderBottom: i < deps.length - 1 ? "1px solid #e8e8e5" : undefined,
   389→                        opacity: selections[i] ? 1 : 0.5,
   390→                      }}
   391→                    >
   392→                      <td className="px-3 py-2.5">
   393→                        <input
   394→                          type="checkbox"
   395→                          checked={!!selections[i]}
   396→                          onChange={(e) => setSelections({ ...selections, [i]: e.target.checked })}
   397→                          className="rounded"
   398→                          style={{ accentColor: "#e8601a" }}
   399→                        />
   400→                      </td>
   401→                      <td className="px-3 py-2.5">
   402→                        <span
   403→                          className="text-[12px]"
   404→                          style={{ fontFamily: "'JetBrains Mono', monospace", color: "#111113" }}
   405→                        >
   406→                          {dep.name}
   407→                        </span>
   408→                      </td>
   409→                      <td className="px-3 py-2.5">
   410→                        <span
   411→                          className="inline-flex items-center rounded px-1.5 py-0.5 text-[11px]"
   412→                          style={{
   413→                            backgroundColor: "#f3f3f1",
   414→                            fontFamily: "'JetBrains Mono', monospace",
   415→                            color: "#374151",
   416→                          }}
   417→                        >
   418→                          {dep.version}
   419→                        </span>
   420→                      </td>
   421→                      <td className="px-3 py-2.5">
   422→                        <span
   423→                          className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium"
   424→                          style={{
   425→                            backgroundColor: eco.bg,
   426→                            color: eco.text,
   427→                            border: `1px solid ${eco.border}`,
   428→                          }}
   429→                        >
   430→                          {dep.ecosystem}
   431→                        </span>
   432→                      </td>
   433→                      <td className="px-3 py-2.5">
   434→                        <span className="text-[12px]" style={{ color: "#6b7280", fontFamily: "'JetBrains Mono', monospace" }}>
   435→                          {dep.upstream_repo}
   436→                        </span>
   437→                      </td>
   438→                      <td className="px-3 py-2.5">
   439→                        <select
   440→                          value={projectAssignments[i]?.mode === "existing" ? projectAssignments[i]?.projectId : "__new__"}
   441→                          onChange={(e) => {
   442→                            const val = e.target.value;
   443→                            if (val === "__new__") {
   444→                              setProjectAssignments({
   445→                                ...projectAssignments,
   446→                                [i]: { mode: "new", newName: dep.name.replace(/\//g, "-") },
   447→                              });
   448→                            } else {
   449→                              setProjectAssignments({
   450→                                ...projectAssignments,
   451→                                [i]: { mode: "existing", projectId: val },
   452→                              });
