   456→                          style={{
   457→                            borderColor: "#e8e8e5",
   458→                            color: "#374151",
   459→                            fontFamily: "var(--font-dm-sans)",
   460→                          }}
   461→                        >
   462→                          <option value="__new__">Create new project</option>
   463→                          {existingProjects.map((p) => (
   464→                            <option key={p.id} value={p.id}>{p.name}</option>
   465→                          ))}
   466→                        </select>
   467→                      </td>
   468→                    </tr>
   469→                  );
   470→                })}
   471→              </tbody>
   472→            </table>
   473→          </div>
   474→        </>
   475→      )}
   476→
   477→      {/* Step 4: Applied */}
   478→      {step === "applied" && applyResult && (
   479→        <>
   480→          <div
   481→            className="rounded-md px-4 py-3 text-[13px]"
   482→            style={{
   483→              backgroundColor: "#f0fdf4",
   484→              border: "1px solid #bbf7d0",
   485→              color: "#15803d",
   486→              fontFamily: "var(--font-dm-sans)",
   487→            }}
   488→          >
   489→            <div className="flex items-center gap-2">
   490→              <Check className="h-4 w-4" />
   491→              Successfully created {applyResult.created_sources.length} source{applyResult.created_sources.length !== 1 ? "s" : ""}
   492→              {applyResult.created_projects.length > 0 && ` and ${applyResult.created_projects.length} project${applyResult.created_projects.length !== 1 ? "s" : ""}`}.
   493→            </div>
   494→          </div>
   495→
   496→          {applyResult.skipped.length > 0 && (
   497→            <div
   498→              className="rounded-md px-4 py-3 text-[13px]"
   499→              style={{
   500→                backgroundColor: "#fefce8",
   501→                border: "1px solid #fde68a",
   502→                color: "#a16207",
   503→                fontFamily: "var(--font-dm-sans)",
   504→              }}
   505→            >
   506→              <p className="font-medium mb-1">Skipped ({applyResult.skipped.length}):</p>
   507→              <ul className="list-disc pl-5 text-[12px]">
   508→                {applyResult.skipped.map((s, i) => <li key={i}>{s}</li>)}
   509→              </ul>
   510→            </div>
   511→          )}
   512→
   513→          <div className="flex gap-3">
   514→            <button
   515→              onClick={() => router.push("/projects")}
   516→              className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90"
   517→              style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   518→            >
   519→              View Projects
   520→              <ArrowRight className="h-3.5 w-3.5" />
   521→            </button>
   522→            <button
   523→              onClick={() => { setStep("input"); setRepoUrl(""); setScanId(null); setScan(null); setApplyResult(null); }}
   524→              className="rounded-md border px-4 py-2 text-[13px] transition-colors hover:bg-[#f3f3f1]"
   525→              style={{
   526→                borderColor: "#e8e8e5",
   527→                color: "#374151",
   528→                fontFamily: "var(--font-dm-sans)",
   529→              }}
   530→            >
   531→              Scan Another Repo
   532→            </button>
   533→          </div>
   534→        </>
   535→      )}
   536→    </div>
   537→  );
   538→}
   539→
   540→/* --- Progress step components --- */
   541→
   542→function ScanStep({ label, done, active }: { label: string; done: boolean; active: boolean }) {
   543→  return (
   544→    <div className="flex items-center gap-1.5">
   545→      <div
   546→        className="flex items-center justify-center rounded-full"
   547→        style={{
   548→          width: 18,
   549→          height: 18,
   550→          backgroundColor: done ? "#f0fdf4" : active ? "#fff7ed" : "#f3f3f1",
   551→          border: `1.5px solid ${done ? "#16a34a" : active ? "#e8601a" : "#e8e8e5"}`,
   552→        }}
   553→      >
   554→        {done ? (
   555→          <Check className="h-3 w-3" style={{ color: "#16a34a" }} />
   556→        ) : active ? (
   557→          <Loader2 className="h-3 w-3 animate-spin" style={{ color: "#e8601a" }} />
