     7→import type { RepoItem, OnboardScan, OnboardSelection, Project, Source } from "@/lib/api/types";
     8→
     9→type Step = "pick" | "scanning" | "results" | "applied";
    10→
    11→const ecosystemColors: Record<string, { bg: string; text: string; border: string }> = {
    12→  go: { bg: "#ecfeff", text: "#0e7490", border: "#a5f3fc" },
    13→  npm: { bg: "#fef2f2", text: "#b91c1c", border: "#fecaca" },
    14→  pypi: { bg: "#fefce8", text: "#a16207", border: "#fde68a" },
