                  <input
                    type="checkbox"
                    checked={!!selections[i]}
                    onChange={(e) => onSelectionsChange({ ...selections, [i]: e.target.checked })}
                    className="rounded"
                    style={{ accentColor: "#e8601a" }}
                  />
                </td>
                <td className="px-3 py-2.5">
                  <span
                    className="text-[12px]"
                    style={{ fontFamily: "'JetBrains Mono', monospace", color: "#111113" }}
