        <SuggestionsSection />
      ) : (
        <DiscoverySection />
      )}

      {/* Quick Onboard inline */}
      <div
        className="rounded-lg bg-white px-5 py-3"
        style={{ border: "1px solid #e8e8e5" }}
      >
        <div className="flex items-center gap-4">
          <span
            className="flex-shrink-0"
            style={{
